        public void testRoundTimeframe()
        {
            var exchange = new ccxt.Exchange(new Dictionary<string, object>() {
                { "id", "sampleexchange" },
            });
            object testDate = exchange.parse8601("2019-08-12 13:22:08");
            Assert(isEqual(exchange.roundTimeframe("5m", testDate, ROUND_DOWN), exchange.parse8601("2019-08-12 13:20:00")));
            Assert(isEqual(exchange.roundTimeframe("10m", testDate, ROUND_DOWN), exchange.parse8601("2019-08-12 13:20:00")));
            Assert(isEqual(exchange.roundTimeframe("30m", testDate, ROUND_DOWN), exchange.parse8601("2019-08-12 13:00:00")));
            Assert(isEqual(exchange.roundTimeframe("1d", testDate, ROUND_DOWN), exchange.parse8601("2019-08-12 00:00:00")));
            Assert(isEqual(exchange.roundTimeframe("5m", testDate, ROUND_UP), exchange.parse8601("2019-08-12 13:25:00")));
            Assert(isEqual(exchange.roundTimeframe("10m", testDate, ROUND_UP), exchange.parse8601("2019-08-12 13:30:00")));
            Assert(isEqual(exchange.roundTimeframe("30m", testDate, ROUND_UP), exchange.parse8601("2019-08-12 13:30:00")));
            Assert(isEqual(exchange.roundTimeframe("1h", testDate, ROUND_UP), exchange.parse8601("2019-08-12 14:00:00")));
            Assert(isEqual(exchange.roundTimeframe("1d", testDate, ROUND_UP), exchange.parse8601("2019-08-13 00:00:00")));
        }
        public void testParseTimeframe()
        {
            var exchange = new ccxt.Exchange(new Dictionary<string, object>() {
                { "id", "sampleexchange" },
            });
            Assert(isEqual(exchange.parseTimeframe("1m"), 60));
            Assert(isEqual(exchange.parseTimeframe("5m"), 300));
            Assert(isEqual(exchange.parseTimeframe("1h"), 3600));
            Assert(isEqual(exchange.parseTimeframe("1d"), 86400));
            Assert(isEqual(exchange.parseTimeframe("1w"), 604800));
            Assert(isEqual(exchange.parseTimeframe("1M"), 2592000)); // todo: just approx
            Assert(isEqual(exchange.parseTimeframe("1y"), 31536000)); // todo: just approx
        }
        public void testTimeframes()
        {
            testRoundTimeframe();
            testParseTimeframe();
        }
}